import 'dart:math';
import 'package:flutter/material.dart';

void main() => runApp(const MaterialApp(home: PainterDemo()));

class PainterDemo extends StatelessWidget {
  const PainterDemo({super.key});
  @override
  Widget build(BuildContext context) => Scaffold(
    appBar: AppBar(title: const Text('CustomPainter demo')),
    body: Center(
      child: SizedBox(
        width: 300, height: 300,
        child: CustomPaint(painter: _RingSmileyPainter(progress: 0.72)),
      ),
    ),
  );
}

class _RingSmileyPainter extends CustomPainter {
  _RingSmileyPainter({required this.progress});
  final double progress;   // 0.0 - 1.0

  @override
  void paint(Canvas canvas, Size size) {
    final center = size.center(Offset.zero);
    final radius = size.shortestSide / 2 * 0.85;

    // 1. Background ring (grey)
    final bg = Paint()
      ..color = Colors.grey.shade300
      ..style = PaintingStyle.stroke
      ..strokeWidth = 20;
    canvas.drawCircle(center, radius, bg);

    // 2. Progress arc — sweeps from top clockwise
    final progressPaint = Paint()
      ..shader = const LinearGradient(colors: [Colors.deepPurple, Colors.pinkAccent])
          .createShader(Rect.fromCircle(center: center, radius: radius))
      ..style = PaintingStyle.stroke
      ..strokeWidth = 20
      ..strokeCap = StrokeCap.round;
    canvas.drawArc(
      Rect.fromCircle(center: center, radius: radius),
      -pi / 2,               // start at 12 o'clock
      2 * pi * progress,     // sweep angle
      false,
      progressPaint,
    );

    // 3. Smiley eyes
    final eye = Paint()..color = Colors.deepPurple;
    canvas.drawCircle(center + const Offset(-30, -20), 8, eye);
    canvas.drawCircle(center + const Offset(30, -20), 8, eye);

    // 4. Smiley mouth — a Path
    final mouth = Path()..moveTo(center.dx - 30, center.dy + 20)
      ..quadraticBezierTo(center.dx, center.dy + 60, center.dx + 30, center.dy + 20);
    canvas.drawPath(
      mouth,
      Paint()..color = Colors.deepPurple..style = PaintingStyle.stroke..strokeWidth = 4,
    );

    // 5. Percentage text (uses TextPainter)
    final tp = TextPainter(
      text: TextSpan(text: '${(progress * 100).toInt()}%',
        style: const TextStyle(fontSize: 28, fontWeight: FontWeight.bold, color: Colors.black)),
      textDirection: TextDirection.ltr,
    )..layout();
    tp.paint(canvas, center + Offset(-tp.width / 2, radius - 40));
  }

  // Only repaint when progress actually changed — free perf.
  @override
  bool shouldRepaint(covariant _RingSmileyPainter old) => old.progress != progress;
}

// Wrap the CustomPaint with an AnimationController + CustomPaint whose delegate
// is rebuilt each frame with the current animation value. This is how you
// build a spinning loader, an animated progress ring, or a waveform.

class AnimatedRing extends StatefulWidget {
  const AnimatedRing({super.key});
  @override State<AnimatedRing> createState() => _AnimatedRingState();
}

class _AnimatedRingState extends State<AnimatedRing> with SingleTickerProviderStateMixin {
  late final _ctrl = AnimationController(vsync: this, duration: const Duration(seconds: 2))..repeat();

  @override
  void dispose() { _ctrl.dispose(); super.dispose(); }

  @override
  Widget build(BuildContext context) => RepaintBoundary(
    // Wrapping in RepaintBoundary isolates the ring's frequent repaints
    // from the surrounding UI — huge perf win.
    child: AnimatedBuilder(
      animation: _ctrl,
      builder: (context, _) => CustomPaint(
        size: const Size(200, 200),
        painter: _RingSmileyPainter(progress: _ctrl.value),
      ),
    ),
  );
}

